import type { PointShapeType } from '../../shape/type.js';
import { useCanvas } from '../hooks/useCanvas.js';
import { getCanvasColor } from '../utils/canvas-color.js';
import { drawSymbol } from '../utils/shapes/symbol-canvas.js';

interface CircleCanvasProps {
  x: number;
  y: number;
  r: number;
  color: string;
  strokeColor?: string;
  strokeWidth?: number;
  opacity?: number;
  shape?: PointShapeType;
}

export const SymbolCanvas = (props: CircleCanvasProps) => {
  const {
    x,
    y,
    r,
    color,
    shape,
    strokeColor = color,
    strokeWidth = 0,
    opacity = 1,
  } = props;

  const draw = (ctx: CanvasRenderingContext2D) => {
    ctx.save();
    ctx.beginPath();

    drawSymbol(ctx, x, y, r, shape);

    ctx.globalAlpha = opacity;
    ctx.fillStyle = getCanvasColor(color);
    ctx.fill();

    // Only stroke if strokeWidth > 0
    ctx.globalAlpha = 1;
    ctx.lineWidth = strokeWidth;
    ctx.strokeStyle = getCanvasColor(strokeColor);
    ctx.stroke();

    ctx.closePath();
    ctx.restore();

    return false;
  };

  useCanvas('symbol', draw);

  return null;
};
